import {spawn} from 'node:child_process';
const port = 34571;
const child = spawn('node', ['src/server.mjs'], {env: {...process.env, PORT: String(port)}, stdio: 'ignore'});
const base = 'http://127.0.0.1:' + port;
let ok = false;
try {
  let up = false;
  for (let i = 0; i < 50 && !up; i++) { try { await fetch(base + '/notes'); up = true; } catch { await new Promise(r => setTimeout(r, 200)); } }
  if (!up) throw new Error('server never responded on PORT');
  const create = await fetch(base + '/notes', {method: 'POST', headers: {'content-type': 'application/json'}, body: JSON.stringify({title: 'probe note', body: 'probe body'})});
  if (create.status !== 201) throw new Error('create expected 201, got ' + create.status);
  const created = await create.json();
  if (!created || created.id === undefined) throw new Error('create response missing id');
  const list = await (await fetch(base + '/notes')).json();
  if (!JSON.stringify(list).includes('probe note')) throw new Error('list missing created note');
  const got = await fetch(base + '/notes/' + created.id);
  if (got.status !== 200) throw new Error('get expected 200, got ' + got.status);
  const del = await fetch(base + '/notes/' + created.id, {method: 'DELETE'});
  if (![200, 204].includes(del.status)) throw new Error('delete expected 200/204, got ' + del.status);
  const missing = await fetch(base + '/notes/' + created.id);
  if (missing.status !== 404) throw new Error('expected 404 after delete, got ' + missing.status);
  const bad = await fetch(base + '/notes', {method: 'POST', headers: {'content-type': 'application/json'}, body: '{'});
  if (bad.status !== 400) throw new Error('invalid body expected 400, got ' + bad.status);
  ok = true;
} finally { child.kill('SIGTERM'); }
if (!ok) process.exit(1);
console.log('PROBE_OK');
